import React from 'react';
import './footer.css';

const Footer = () => {
  return (
    <footer id="footer">
      {/* Le contenu du footer */}
      <p>
        Contact Christian Dupont <br />
        26 rue des Allées <br /> 75000 Paris
        <br />
        Tel: 06-01-01-01-01
      </p>
      <p>
        Réalisé par Christian Dupont
        <br /> © copyright 2023
      </p>
    </footer>
  );
};

export default Footer;
